interface MyInterface {
    void normalMethod();

    default void defaultMethod() {
        System.out.println("Default implementation");
    }

    static void staticMethod() {
        System.out.println("Static method in interface");
    }
}

class MyClass implements MyInterface {
    @Override
    public void normalMethod() {
        System.out.println("Normal method implemented");
    }

    // Optional: Override default method
    @Override
    public void defaultMethod() {
        System.out.println("Overridden default method");
    }
}

public class InterfaceMethodDemo {
    public static void main(String[] args) {
        MyClass obj = new MyClass();
        obj.normalMethod();
        obj.defaultMethod();
        MyInterface.staticMethod();  // Called with interface name
    }
}

@FunctionalInterface
interface Calculator {
    int calculate(int a, int b);  // Single abstract method

    default void display() {
        System.out.println("Default method allowed");
    }
}

public class FunctionalInterfaceDemo {
    public static void main(String[] args) {
        // Using lambda expression
        Calculator add = (a, b) -> a + b;
        Calculator multiply = (a, b) -> a * b;

        System.out.println("Addition: " + add.calculate(10, 20));
        System.out.println("Multiplication: " + multiply.calculate(10, 20));

        add.display();
    }
}

